// UFPR - Residencia Medica 2019 (Edital 71/2019-HC, 68/2019-HT), Acesso Direto, prova 101
export const UFPR_2019_101_QUESTIONS: any[] = [
  { id: 'ufpr_2019_101_001', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Paciente de 56 anos, sexo masculino, queixa-se de aumento do peso corporal após o início de um medicamento para o tratamento do diabete mellitus tipo 2. O medicamento que tem maior relação com o aumento do peso corporal e que provavelmente esse paciente esteja tomando é:', options: ['liraglutida.', 'glimepirida.', 'empagliflozina.', 'metformina.', 'saxagliptina.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_002', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Com base nas doenças causadas por deficiência vitamínica, numere a coluna da direita relacionando a vitamina com a respectiva doença. 1. Pelagra. 2. Síndrome Wernicke-Korsakoff. 3. Escorbuto. 4. Osteomalacia. 5. Anemia megaloblástica. ( ) Vitamina B1. ( ) Vitamina D. ( ) Vitamina B3. ( ) Vitamina C. ( ) Vitamina B9. Assinale a alternativa que apresenta a numeração correta da coluna da direita, de cima para baixo.', options: ['2 – 4 – 1 – 3 – 5.', '4 – 1 – 5 – 3 – 2.', '3 – 4 – 5 – 2 – 1.', '1 – 5 – 4 – 3 – 2.', '2 – 5 – 4 – 3 – 1.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_003', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Os medicamentos diuréticos da classe dos tiazídicos são medicamentos importantes no tratamento da hipertensão arterial sistêmica. Apesar dos benefícios comprovados, esses medicamentos podem apresentar alguns efeitos colaterais que devem ser monitorados especialmente na população idosa. São todos efeitos colaterais associados ao uso dos diuréticos tiazídicos, EXCETO:', options: ['fotossensibilidade cutânea.', 'hiponatremia.', 'hipocalcemia.', 'hiperuricemia.', 'hipopotassemia.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_004', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Paciente de 78 anos, sexo feminino, refere estar fazendo um tratamento devido a uma fratura espontânea no corpo vertebral T12 secundária à osteoporose. Não recorda o nome do medicamento, porém relata utilizar o remédio através de uma injeção subcutânea diária. Lembra que o médico orientou o seu uso pelo período máximo de 18 a 24 meses devido ao risco de desenvolvimento de osteossarcoma com o uso mais prolongado. A partir do exposto, é correto afirmar que essa paciente está utilizando:', options: ['alendronato de sódio.', 'denosumabe.', 'raloxifeno.', 'ácido zoledrônico.', 'teriparatida.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_005', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Paciente de 69 anos, sexo masculino, portador de diabete mellitus tipo 2 e hipertensão arterial sistêmica, está em acompanhamento devido a um infarto agudo do miocárdio com colocação de um stent na artéria coronária descendente anterior e circunflexa há 2 anos. Atualmente em uso de rosuvastatina 40 mg ao dia e AAS 100 mg ao dia. A despeito do uso de uma estatina, seu LDL colesterol é 145 mg/dL. Esse paciente pode adicionar ao tratamento um dos seguintes medicamentos, EXCETO:', options: ['ezetimibe.', 'evolocumabe.', 'alirocumabe.', 'ácido nicotínico.', 'colestiramina.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_006', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Um homem de 56 anos, obeso, está em acompanhamento devido a discreta elevação das transaminases. Apresenta os seguintes exames para o vírus da hepatite C: anticorpo anti-VHC positivo; RNA VHC não detectado. Qual é a interpretação desses dois exames?', options: ['Hepatite C fase aguda.', 'Infecção passada pelo vírus da hepatite C com cura espontânea.', 'Infecção crônica pelo vírus da hepatite C em paciente imunocompetente.', 'Infecção crônica pelo vírus da hepatite C em paciente imunodeprimido.', 'Hepatite C fase indeterminada.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_007', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Numere a coluna da direita, relacionando os casos clínicos com os respectivos tratamentos para o diabetes mellitus. 1. Paciente de 71 anos, sexo masculino, glicemia de jejum 145 mg/dL, refere que teve de aumentar a dose do medicamento furosemida utilizado para o tratamento da insuficiência cárdica com fração de ejeção reduzida após o início. 2. Paciente de 60 anos, sexo masculino, glicemia de jejum 160 mg/dL, refere que seu médico orientou a suspensão do medicamento em uso para o tratamento do diabetes pois a sua taxa de filtração glomerular estava inferior a 30 mL/min. 3. Paciente de 79 anos, sexo feminino, hemoglobina glicosilada 7,1%, é admitida no serviço de emergência devido a alteração do nível de consciência secundária a uma hipoglicemia. ( ) Metformina. ( ) Gliclazida. ( ) Pioglitazona. ( ) Insulina glargina. Assinale a alternativa que apresenta a numeração correta na coluna da direita, de cima para baixo.', options: ['1 – 1 – 3 – 2.', '3 – 2 – 1 – 3.', '2 – 3 – 1 – 3.', '1 – 3 – 2 – 2.', '2 – 2 – 3 – 1.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_008', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'A partir dos achados laboratoriais na coluna da esquerda, numere as patologias da coluna da direita. 1. Bilirrubina indireta 1,8 mg/dL. 2. Hemoglobina corpuscular média (HCM) 20 pg. 3. Concentração hemoglobinica corpuscular média (CHCM) 37 g/dL. 4. RDW 16,5%. 5. Contagem de plaquetas 85.000 /µL. ( ) Anemia ferropriva. ( ) Anemia por deficiência de vitamina B12. ( ) Talassemia. ( ) Mielodisplasia. ( ) Esferocitose. Assinale a alternativa que apresenta a numeração correta na coluna da direita, de cima para baixo.', options: ['4 – 1 – 2 – 5 – 3.', '4 – 2 – 1 – 5 – 3.', '1 – 2 – 3 – 4 – 5.', '1 – 3 – 2 – 4 – 5.', '5 – 1 – 3 – 2 – 4.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_009', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Paciente feminina de 18 anos procura atendimento devido a dor de garganta e febre há três dias. Também apresenta cefaleia, dor abdominal, náuseas e êmese. Refere persistência de quadro de fadiga e mialgia, que iniciou duas semanas antes da primeira febre. Nega comorbidades ou uso de medicamentos. Nega relação desprotegida. Apresenta FC 96/min, PA 118/78 mmHg, FR 14/min, temperatura 38,0 ºC, e SpO2 99% em ar ambiente. Ao exame físico, destacam-se hiperemia e exsudato em faringe, linfonodomegalia cervical, icterícia, hepatimetria = 15 cm e espaço de Traube ocupado. Exames laboratoriais demonstram: Hb = 11,4 g/dL; VG = 34%; VCM = 90,1 fL; HCM = 30,2 pg; CHCM = 33,9 g/dL; RDW = 17%; leucócitos = 10.012/mm3; linfócitos = 7.147/mm3; linfócitos atípicos = 4.211/mm3; plaquetas = 96.500/mm3; ALT = 128 U/L; AST = 133 U/L; FA = 174 U/L; GGT 55 U/L; BT = 3,4 mg/dL; BD = 0,9 mg/dL; LDH = 451 U/L. A pesquisa de anticorpos heterófilos foi positiva (considere especificidade = 100%). Considerando a principal hipótese diagnóstica, qual é o agente etiológico?', options: ['Vírus da hepatite A.', 'Estreptococo.', 'EBV.', 'CMV.', 'HIV.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_010', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'São consideradas complicações ou doenças associadas à mononucleose infecciosa (EBV), EXCETO:', options: ['linfoma.', 'encefalite.', 'hepatite fulminante.', 'síndrome de Guillain-Barré.', 'anemia hemolítica por anticorpos quentes.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_011', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Entre os fatores abaixo relacionados, qual é o de maior risco para infarto do miocárdio?', options: ['Diabetes.', 'Obesidade.', 'Tabagismo.', 'Hipertensão.', 'Dislipidemia.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_012', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Paciente de 68 anos, sexo feminino, portadora de doença arterial coronariana, em uso de AAS 100 mg ao dia, procura assistência médica devido a dor epigástrica. É realizada uma endoscopia digestiva alta que mostra a presença de uma úlcera gástrica, a qual é submetida a biópsia. Histologia mostra a presença da bactéria Helicobacter pylori. A paciente é orientada a fazer o tratamento para a erradicação com esomeprazol, claritromicina e amoxicilina durante 14 dias e, após 30 dias do término do tratamento proposto, realizar um novo exame para verificar se houve a erradicação da bactéria. São exames utilizados para essa finalidade, EXCETO:', options: ['histologia.', 'teste da urease.', 'pesquisa do antígeno fecal.', 'teste da ureia respiratória.', 'sorologia IGG; IGM.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_013', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Um jovem de 18 anos, sexo masculino, refere início de febre, coriza, tosse e conjuntivite três dias após retornar de uma viagem à cidade de Nova Iorque, nos Estados Unidos. Relata ter permanecido no bairro do Brooklyn daquela cidade durante 45 dias para realizar um curso de aperfeiçoamento em inglês. Ao exame físico, é observada a presença de pequenas máculas de coloração branca azulada na mucosa bucal. O paciente relata que seus pais são contrários ao uso de vacinas e que, por esse motivo, ele não fez as vacinas recomendadas. Qual a principal hipótese diagnóstica?', options: ['Sarampo.', 'Mononucleose infecciosa.', 'Influenza.', 'Escarlatina.', 'Citomegalovírus.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_014', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'São causas de esplenomegalia maciça, EXCETO:', options: ['anemia hemolítica autoimune.', 'leucemia linfocítica crônica.', 'policitemia vera.', 'drepanocitose.', 'mielofibrose.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_015', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Paciente masculino de 76 anos procura a emergência devido à preocupação com resultado de exame laboratorial alterado. Nega sintomas. Apresenta história de fibrilação atrial, dislipidemia, diabetes e hipertensão arterial. Faz uso de rosuvastatina 20 mg ao dia, metformina 850 mg duas vezes ao dia e enalapril 20 mg ao dia. Apresenta FC 68/min, PA 134/80 mmHg, FR 12/min, temperatura 36,7 ºC, e SpO2 99% em ar ambiente. Ao exame físico, não se constata equimose, hematoma ou sangramentos. Revisão de sistemas é negativa. Exame laboratorial trazido demonstra tempo de protrombina/INR = 8,5. Qual é a conduta correta para esse caso, segundo guidelines recentes?', options: ['Omitir varfarina até nível terapêutico e, então, reiniciar varfarina com redução de 10-15% na dose semanal.', 'Administrar vitamina K oral e omitir varfarina até nível terapêutico e, então, reiniciar varfarina com redução de 10-15% na dose semanal.', 'Administrar vitamina K parenteral e omitir varfarina até nível terapêutico e, então, reiniciar varfarina com redução de 10-15% na dose semanal.', 'Administrar plasma fresco congelado e omitir varfarina até nível terapêutico e, então, reiniciar varfarina com redução de 10-15% na dose semanal.', 'Administrar concentrado de complexo protrombínico e omitir varfarina até nível terapêutico e, então, reiniciar varfarina com redução de 10-15% na dose semanal.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_016', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Dermatologia', text: 'Considere a seguinte descrição de uma doença: Caracteriza-se pelo desenvolvimento abrupto de numerosas pústulas não foliculares sobre áreas de eritema difuso com edema, que pode evoluir para eritrodermia, acompanhado por febre alta e leucocitose. Pode haver confluência das lesões com sinal de Nikolsky positivo, além de acometimento eventual de membranas mucosas, geralmente da cavidade oral. Há predomínio neutrofílico na série branca do hemograma, comumente acima de 7.000/mm3. Biópsia de pele demonstra coleções de neutrófilos e necrose esparsa de queratinócitos na porção superior da epiderme. É ocasionada por exposição a drogas em mais de 90% dos casos, sendo a classe dos betalactâmicos a responsável pela maioria dos casos. O intervalo entre a exposição à droga e o desenvolvimento de sintomas é de geralmente 24 a 48 horas, com tempo médio de 1 a 11 dias. Pode haver acometimento visceral, como hepatite, nefrite e pneumonite. O manejo se dá por suspensão da droga identificada como gatilho, tratamento suportivo, e corticoterapia sistêmica e/ou tópica. Qual é a doença descrita?', options: ['Síndrome da hipersensibilidade induzida por droga (DIHS).', 'Pustulose exantemática generalizada aguda.', 'Síndrome de Stevens-Johnson.', 'Psoríase pustulosa aguda.', 'Acne fulminans.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_017', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Endocrinologia', text: 'São manifestações clínico-laboratoriais da doença de Addison, EXCETO:', options: ['hipotensão.', 'hipocalemia.', 'hipoglicemia.', 'hiponatremia.', 'hipocortisolismo.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_018', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Neurologia', text: 'O par craniano acometido inicialmente com mais frequência no aumento da pressão intracraniana é:', options: ['III.', 'IV.', 'V.', 'VI.', 'VII.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_019', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pneumologia', text: 'De acordo com o estudo ADJUST-PE e com o Comitê de Guidelines Clínicos do ACP (American College of Physicians), considere os seguintes cenários quanto ao valor de corte de D-dímero (por ELISA, de nova geração) a ser utilizado para determinar necessidade de solicitação de imagem na suspeita de tromboembolismo pulmonar: 1. Paciente masculino de 40 anos: corte de D-dímero = 400 ng/mL. 2. Paciente feminina de 50 anos: corte de D-dímero = 500 ng/mL. 3. Paciente masculino de 60 anos: corte de D-dímero = 600 ng/mL. Está/Estão correto(s) o(s) item(ns):', options: ['3 apenas.', '1 e 2 apenas.', '1 e 3 apenas.', '2 e 3 apenas.', '1, 2 e 3.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_020', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pneumologia', text: 'O Comitê de Guidelines Clínicos do ACP (American College of Physicians) preconiza a utilização de escores de avaliação, exames laboratorial e de imagem na estratificação da probabilidade diagnóstica de tromboembolismo pulmonar (TEP) em adultos (exceto gestantes), conforme o contexto clínico individualizado. Analise os cenários a seguir, considerando uma paciente feminina de 30 anos, oriunda de população com baixa prevalência de TEP; para cálculo de probabilidade, utilizam-se os critérios de Wells; aplicam-se os critérios PERC (Pulmonary Embolism Rule-out Criteria) na etapa preconizada quando aplicável; e D-dímero por ELISA (nova geração). Em qual cenário permite-se excluir TEP por meio do uso correto do algoritmo diagnóstico e das ferramentas complementares, isto é, sem desperdício de alguma etapa?', options: ['Wells: probabilidade baixa → PERC: seis critérios não preenchidos → exclusão TEP.', 'Wells: probabilidade baixa → PERC: todos critérios preenchidos → D-dímero: 180 ng/mL → exclusão TEP.', 'Wells: probabilidade baixa → PERC: um critério não preenchido → D-dímero: 790 ng/mL → AngioTC: negativa → exclusão TEP.', 'Wells: probabilidade intermediária → D-dímero: 600 ng/mL → exclusão TEP.', 'Wells: probabilidade alta → D-dímero: 820 ng/mL → AngioTC: negativa → exclusão TEP.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_021', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Infecção cirúrgica inclui qualquer infecção que acomete o paciente cirúrgico. A respeito do assunto, considere as seguintes afirmativas: 1. Idade acima de 65 anos é considerada fator de risco. 2. Hiperglicemia prejudica a imunidade celular do paciente cirúrgico. 3. Transfusão sanguínea está associada a aumento da imunidade contra as infecções. 4. Hipotermia é considerada um mecanismo de proteção conta infecção cirúrgica. Assinale a alternativa correta.', options: ['Somente a afirmativa 2 é verdadeira.', 'Somente as afirmativas 1 e 2 são verdadeiras.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_023', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'A principal causa de febre pós-operatória nas primeiras 48 horas pós-cirúrgicas é:', options: ['pneumonia aspirativa.', 'atelectasia pulmonar.', 'trombose venosa profunda.', 'infecção do sítio cirúrgico.', 'tromboembolismo pulmonar.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_024', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação à resposta metabólica no paciente cirúrgico, é INCORRETO afirmar:', options: ['Após o estresse agudo, ocorre uma rápida mobilização dos depósitos de gordura por meio da ativação da lipase.', 'O trauma cirúrgico leva ao aumento da resistência à insulina.', 'Cetogênese é incrementada como consequência da ativação inflamatória que segue ao trauma cirúrgico.', 'Nos pacientes em que o trauma se prolonga, pode ocorrer um estado de catabolismo refratário.', 'A glicogenólise é estimulada por hormônios liberados após aumento das citocinas pró-inflamatórias.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_025', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Paciente masculino, 57 anos de idade, apresenta queixas de queimação retroesternal, referindo por vezes regurgitação. Com a suspeita de doença do refluxo gastroesofageano (DRGE), o exame considerado padrão-ouro para a confirmação diagnóstica é:', options: ['raios x contrastado de esôfago.', 'pH metria de 24 horas.', 'esofagomanometria.', 'endoscopia digestiva alta.', 'tomografia computadorizada de abdome superior.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_026', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação ao diagnóstico de esôfago de Barrett, assinale a alternativa correta.', options: ['A principal causa esôfago de Barrett é o refluxo alcalino ao esôfago distal.', 'O epitélio do esôfago distal é substituído por epitélio juncional.', 'A incidência de adenocarcinoma de esôfago é elevada no paciente que apresenta esôfago de Barrett.', 'Pacientes submetidos a tratamento cirúrgico da DRGE irão apresentar regressão da metaplasia.', 'A presença de displasia na biópsia indica aumento do risco de adenocarcinoma.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_027', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Paciente, 62 anos de idade, sexo masculino, foi submetido há 6 meses à hemicolectomia direita por adenocarcinoma de cólon. Durante o acompanhamento pós-operatório, o exame de tomografia de abdome mostra lesões hepáticas compatíveis com metástases de câncer colorretal em ambos os lobos hepáticos. Nesse caso, a melhor conduta é:', options: ['cirurgia citorredutora por meio de ressecção da lesão de maior tamanho.', 'radioterapia seguida de ressecção hepática.', 'transplante hepático.', 'quimioterapia, sistêmica ou quimioembolização intra-arterial, seguida de ressecção hepática.', 'acompanhamento e tratamento dos sintomas quando estes surgirem.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_028', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Paciente, 73 anos de idade, sexo feminino, IMC 23, apresenta quadro de dor abdominal de forte intensidade e de início súbito, localizada no mesogástrio. Ao exame físico, observa-se taquicardia, sem distensão abdominal e sem sinais de irritação peritoneal. Exames laboratoriais mostram hemograma sem alterações significativas, uma gasometria com acidose metabólica e lactato de 7,3 mmol/L. Em relação à paciente, o exame de imagem que deverá ser solicitado na sequência é:', options: ['endoscopia digestiva alta.', 'ultrassonografia de abdome total.', 'tomografia computadorizada do abdome.', 'colonoscopia.', 'radiografia simples de abdome.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_029', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Paciente, 73 anos de idade, sexo feminino, IMC 23, apresenta quadro de dor abdominal de forte intensidade e de início súbito, localizada no mesogástrio. Ao exame físico, observa-se taquicardia, sem distensão abdominal e sem sinais de irritação peritoneal. Exames laboratoriais mostram hemograma sem alterações significativas, uma gasometria com acidose metabólica e lactato de 7,3 mmol/L. O provável tipo de abdome agudo para esse caso é:', options: ['vascular ou isquêmico.', 'hemorrágico.', 'infeccioso.', 'perfurativo.', 'obstrutivo.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_030', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Vascular', text: 'No que diz respeito aos aneurismas da aorta abdominal, considere as seguintes afirmativas: 1. A maioria dos aneurismas é de natureza degenerativa, em contraste com os aneurismas infecciosos (micóticos), inflamatórios, ou doença do tecido conjuntivo. 2. Hipercolesterolemia, tabagismo, hipertensão e sexo masculino são condições associadas ao desenvolvimento do aneurisma. 3. O principal preditor para o risco de ruptura do aneurisma é a sua extensão em comprimento: quanto mais longo o aneurisma, maior o risco de ruptura. 4. Tratamento cirúrgico deve ser recomendado para aneurismas com diâmetro máximo de 5,5 cm e que apresentem crescimento superior a 5 mm em 6 meses, ou 1 cm em 1 ano. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 1, 2 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_031', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'A neoplasia maligna hepática mais comum é:', options: ['o hepatocarcinoma.', 'o tumor metastático.', 'o hepatoblastoma.', 'o colangiocarcinoma.', 'a hiperplasia nodular focal.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_032', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'São indicações de tratamento cirúrgico na colite ulcerativa, EXCETO:', options: ['manifestações extraintestinais.', 'displasia.', 'intratabilidade.', 'hemorragia colônica intensa.', 'megacólon tóxico.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_033', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação aos pólipos do cólon e reto, considere as seguintes afirmativas: 1. Adenoma tubular é o tipo mais comum de pólipo colônico, correspondendo de 65 a 80% dos pólipos ressecados. 2. Na polipose adenomatosa familial, 100% dos pacientes que não forem tratados cirurgicamente irão desenvolver câncer colorretal. 3. Os pólipos benignos podem se desenvolver em câncer colorretal. 4. Pólipos adenoma vilosos, quando maiores que 2 cm de diâmetro, têm uma chance de 50% de serem câncer. Assinale a alternativa correta.', options: ['Somente a afirmativa 4 é verdadeira.', 'Somente as afirmativas 1 e 4 são verdadeiras.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 1, 2 e 3 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_034', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Qual tipo celular é mais prevalente na fase inicial da cicatrização das feridas?', options: ['Linfócito.', 'Plasmócito.', 'Fibroblasto.', 'Neutrófilo.', 'Célula epitelial.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_035', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Sobre o trauma abdominal penetrante, assinale a alternativa INCORRETA.', options: ['Instabilidade hemodinâmica, peritonite e evisceração são indicativos de laparotomia exploradora.', 'Exploração local da ferida deve ser realizada, quando não houver indicação para laparotomia exploradora, com a finalidade de verificar integridade da aponeurose.', 'Pacientes com lesão por projetil de arma de fogo devem ser submetidos à tomografia computadorizada para planejamento cirúrgico.', 'Queda significativa na hemoglobina é indicação para laparotomia exploradora.', 'Quando a exploração local da ferida resultar negativa, o paciente poderá ser encaminhado para domicílio.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_036', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Considere o seguinte caso clínico: Paciente, sexo masculino, 30 anos, vítima de colisão auto x auto, frontal, de alta energia, chega ao pronto-socorro trazido por populares. O exame inicial indica: a) vias aéreas não pérvias, dificuldade de fala, sem colar cervical e sem tábua rígida; b) expansibilidade torácica diminuída à esquerda, MV diminuído à esquerda, maciço à percussão em hemitórax esquerdo e presença de enfisema subcutâneo abaixo da linha mamilar esquerda, saturação de 88%, O2 em 5 L/min; c) bulhas cardíacas rítmicas normofonéticas sem sopros, FC de 133 bpm, PA inaferível, pulsos periféricos ausentes e entrais cheios, abdome flácido globoso com equimose horizontal abaixo da cicatriz umbilical, pelve estável; d) Glasgow 10 (4 + 1 + 5), pupilas isocóricas e foto-reagentes; e) múltiplos ferimentos cortocontusos em face; fratura nasal com exposição de cartilagem e sangramento ativo, equimose horizontal abaixo da cicatriz umbilical, em todo abdome e diagnonal no ombro esquerdo até crista ilíaca direita. Em relação ao paciente, considere as seguintes afirmativas: 1. A primeira medida a ser tomada deve ser a intubação orotraqueal. 2. Após a intubação orotraqueal, o paciente deve ser submetido à drenagem torácica fechada à esquerda. 3. Deve-se administrar de 1-2 litros de cristaloides em acesso venoso periférico calibroso e avaliar a resposta hemodinâmica; caso não apresente melhora, deverá ser submetido a transfusão sanguínea de sangue não-tipado. 4. Devido à instabilidade hemodinâmica, o FAST (Focused Abdominal Ultrassonography in Trauma) não é indicado. Assinale a alternativa correta.', options: ['Somente a afirmativa 4 é verdadeira.', 'Somente as afirmativas 1 e 2 são verdadeiras.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 1, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_037', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação aos cálculos de vesícula biliar, considere as seguintes afirmativas: 1. O sintoma de cólica biliar está associado à obstrução temporária do ducto cístico pelo cálculo biliar. 2. A maioria dos pacientes com cálculos de vesícula biliar é assintomática. 3. Pacientes com cálculos de vesícula > 2,5 cm devem ser submetidos à colecistectomia, mesmo sem apresentarem sintomas. 4. A fisiopatologia da formação dos cálculos de colesterol está relacionada ao percentual relativo dos componentes da bile – colesterol, lecitina e sais biliares. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 2 e 4 são verdadeiras.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2 e 3 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_038', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Paciente do sexo feminino, 68 anos de idade, realiza ecografia abdominal de rotina, que mostra lesão cística em região de corpo/cauda de pâncreas. Ressonância magnética (RM) de abdome mostra lesão cística em corpo/cauda de pâncreas, medindo 3 cm de diâmetro, com paredes lisas, porém espessadas, e ducto pancreático principal medindo 7 mm. Diante desse quadro, a conduta mais adequada é:', options: ['ecografia endoscópica para determinação de envolvimento do ducto principal e ressecção cirúrgica caso o envolvimento esteja presente.', 'ressecção pancreática, sem outra investigação, pelo risco aumentado de carcinoma.', 'acompanhamento com RM a cada 1-2 anos.', 'ecografia endoscópica para realização de biópsia, e indicação de ressecção cirúrgica somente com comprovação histológica de malignidade.', 'como se trata de lesão cística, não existe risco para malignidade, e, portanto, a paciente não necessita de acompanhamento.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_039', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Levando em consideração a classificação de Nyhus das hérnias inguinais, considere as seguintes afirmativas: 1. Na população pediátrica, as hérnias são do tipo I. 2. Hérnias inguinais associadas com defeito da parede posterior são classificadas como tipo III. 3. Hérnias femorais são classificadas como tipo IV. 4. Hérnia inguinal associada à dilatação do ânulo inguinal interno, porém com parede posterior íntegra, é classificada como tipo II. Assinale a alternativa correta.', options: ['Somente a afirmativa 4 é verdadeira.', 'Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 1, 2 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_040', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Qual o significado clínico do achado de equimose horizontal em abdome e diagonal em tórax?', options: ['Contusão pulmonar.', 'Lesão mesentérica.', 'Perfuração de bexiga.', 'Perfuração esofágica.', 'Fratura pélvica.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_041', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'ABR, 40 anos, branca, casada, atualmente com idade gestacional de 28 semanas (ecografia realizada na 8ª semana). Procurou o pronto atendimento com queixa de cefaleia occipital e nucalgia. Iniciou seu pré-natal no primeiro trimestre, HAS crônica em uso de metildopa 1,0 g ao dia, cálcio 2 g ao dia e AAS 100 mg ao dia. Realizou exames laboratoriais de rotina de pré-natal (1º e 2° trimestres) com resultados normais. G2C1 há 2 anos por pré-eclâmpsia grave, RN: 710 g, < P5, 29 semanas, óbito neonatal). Exame físico: PA: 160/115 mmHg, peso: 85 kg, FC: 84 bpm, Sat.O2: 97%, estatura: 165 cm, IMC: 32, AU: 25 cm, BCF: 140 bpm, dinâmica uterina: ausente, toque vaginal: colo longo, grosso, posterior e impérvio. Realizada a internação, foram coletados exames laboratoriais, suspenso AAS, administrado hidralazina 5 mg EV diluído e sulfato de magnésio pelo esquema de Pritchard. Exames laboratoriais: ácido úrico: 6,2 mg/dL, LDH = 400 U/L, creatinina: 0,9 mg%, plaquetas: 204.000/mm³. Hb: 13 g/dL, VG: 39%, TGO: 22 U/L. Relação proteinúria/creatinúria: 2,5 g/mol, ecografia com Doppler 28 semanas: PFE: 750g, P10, ILA: 75 mm, artérias uterinas com incisuras protodiastólicas bilaterais, o IR da artéria umbilical: 0,70 e IR da artéria cerebral média: 0,80. Relação U/C < 1,0, ducto venoso: IP < 1,5 e onda A presente. Cardiotocografia normal. Evoluiu assintomática, pressão arterial bem controlada, estabilizada por 24 horas e vitalidade fetal permaneceu normal. Qual é a conduta obstétrica correta nesse momento?', options: ['Encaminhar à enfermaria de alto risco, prescrever corticoide, manter a metildopa, suspender o sulfato de magnésio, realizar exames laboratoriais de 48/48 horas e verificar vitalidade fetal diariamente com o objetivo de alcançar a 37ª semana.', 'Prescrever corticosteroide antenatal, sulfato de magnésio em bomba, nifedipino 10 mg por via sublingual de 8/8 horas e proceder à realização da cesariana em até 48 horas, sem controle materno-fetal obtido.', 'Manter a internação, prescrever sulfato de magnésio em bomba, repetir os exames laboratoriais, verificar vitalidade fetal e prescrever misoprostol por um máximo de 12 horas.', 'Realizar cesariana de imediato.', 'Dar alta, sem a realização do parto, realizar monitorização e tratamento ambulatorial da PA, repetir exames laboratoriais, verificar vitalidade fetal e retornos semanais.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_042', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'MCS, 24 anos, G3P3, parto transpélvico há 12 dias, comparece ao pronto atendimento com queixa de mal-estar, sonolência e febre, de início há 3 dias e com piora hoje. Apresenta regular estado geral, escala de coma de Glasgow:15, PA: 86/46 mmHg, FC:104 bpm, FR:24, T: 39,6 ºC. Ao exame segmentar, apresenta ausculta torácica e precordial sem alterações exceto taquicardia, mamas com apojadura, saída de leite à expressão, mamilos sem fissuras, abdome flácido, dor moderada à palpação de andar inferior, sem dor à descompressão, útero palpável 4 cm abaixo da cicatriz umbilical. Exame especular apresenta sangramento escurecido moderado, ativo pelo orifício cervical externo, com odor fétido. Ao toque vaginal, dor à mobilização de colo. Membros inferiores com edema +/IV, simétrico, bilateral, com panturrilhas livres. Tendo como base o diagnóstico de sepse no ciclo gravídico-puerperal para esse caso, assinale a alternativa correta.', options: ['A sepse é de origem endometrial e há indicação de solicitar hemograma, gasometria arterial, hemocultura e urinálise, e aguardar resultados desses exames para iniciar tratamento.', 'A sepse é de origem endometrial e há indicação de restaurar o volume circulatório e oferecer adequada oxigenação em ambiente de terapia intensiva, além de iniciar antibioticoterapia empírica até o resultado das culturas.', 'Nesse caso, é fundamental, no manejo da paciente, o controle glicêmico, uma vez que a relação entre hemoglobina glicada, baixas taxas de glicemia e morte em pacientes críticos é bem conhecida.', 'A sequência que levou a paciente à sepse foi a dor à mobilização cervical do colo, o odor fétido e taquicardia.', 'A sepse da paciente é considerada grave por apresentar disfunção de órgão, hipertensão, taquicardia e sangramento escurecido.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_043', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'CD, 30 anos, G1, 37+2 semanas, pré-natal de baixo risco, vem à consulta de rotina solicitando resolução da gestação por cesariana. Refere ter receio da dor do parto e muito medo de óbito fetal, já que sua irmã teve um óbito fetal intraparto recente. Com relação à operação cesariana, assinale a alternativa INCORRETA.', options: ['A cesariana a pedido representa 14 a 22% de todas as cesarianas eletivas e, para a plena fluência dessa problemática na prática obstétrica, os aspectos éticos e legais devem ser cuidadosamente trabalhados por meio do consentimento informado.', 'Além de todos os cuidados de antissepsia adotados, a antibioticoprofilaxia deve ser medida rotineira na cesariana e deve ser realizada antes do início do procedimento.', 'Dentre as complicações da cesariana para o futuro reprodutivo, destaca-se a placentação inadequada junto à cicatriz uterina anterior, o que predispõe à placenta prévia e ao acretismo placentário.', 'Ainda que a cesariana possa ser realizada a pedido da paciente, o médico assistente deve lembrá-la de que as próximas gestações necessariamente deverão ser resolvidas por cesariana, respeitando o princípio de Cragin, de que "uma vez cesárea, sempre cesárea".', 'A cesariana a pedido antes de 39 semanas de gestação não é recomendada para mulheres que desejam vários filhos.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_044', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'VMS, 34 anos, branca, casada, ensino médio completo, em consulta de rotina do seu pré-natal de alto risco, na 36ª semana de gestação, DM tipo 2 há 7 anos e sem queixas. Utilizando insulinas NPH e regular (80/10 unidades - divididas: 2 vezes ao dia). Houve aumento das doses de insulina, conforme perfil glicêmico, durante toda a gestação. DUM: 26/03/2018, DPP: 02/01/2019 (Data desse atendimento: 04/12/2018). História Obstétrica: G3P2 (gravidez 1: 2005, parto transpélvico, 36ª semana, P: 2000g e gravidez 2: 2007, parto vaginal a fórceps, 41 semanas, P: 4990g). Ambos os RNs com boa evolução. Exame físico: PA: 100/60 mmHg, FCM: 80 bpm, peso (pré-gestacional): 82 kg, estatura: 170 cm, IMC (pré-gestacional): 29, peso atual: 90 kg, AU: 40 cm, dinâmica uterina: ausente, BCF: 130 bpm. Toque vaginal: colo grosso, médio, posterior, pérvio para 1 polpa digital. Apresentação cefálica em plano de De Lee –2. Ecocardiografia fetal e ecografia morfológica normais. Ecografias: IG:33 sem, PFE=2310 g(P75), CA=300 mm(P75), placenta: anterior G0, ILA: 228 mm. IG:35 sem, PFE=3135 g(P94), CA: 353 mm(P95), placenta anterior G1, ILA: 335 mm. Exames laboratoriais normais (nos 3 trimestres): exceto Hb glicada (A1C): 9,1% - 6,9% - 7,5% respectivamente e os perfis glicêmicos com mau controle nos últimos 30 dias. Internamento em 04/12/2018 para o Centro Obstétrico. Conduta do plantão: misoprostol 25 ug via vaginal de 6/6 horas + ocitocina na fase ativa. Evoluiu para parto transpélvico em 13 horas. Sobre as complicações perinatais nesse momento, considere as seguintes afirmativas: 1. A hiperinsulinemia fetal inibe a ação do cortisol no pulmão fetal, levando à inibição da produção de lecitina pelo pneumócito tipo 2 e ao desenvolvimento da síndrome do desconforto respiratório do recém-nascido. 2. A policitemia neonatal é decorrente da hiperglicemia e hiperinsulinemia fetais, que ocasionam diminuição do oxigênio livre arterial e estímulo da eritropoese. 3. Na Teoria de Pedersen, a normoglicemia materna acarretaria a hiperglicemia fetal, hiperplasia e hipertrofia das células-beta pancreáticas fetais e a macrossomia fetal. 4. A macrossomia fetal, recém-nascido com peso superior a 4.000 g, está associada ao diabetes não compensado e maiores riscos de distócia de ombro e tocotraumatismos. 5. A hipoglicemia neonatal, valor de glicemia sérica inferior a 70 mg/dL, em recém-nascido a termo nas primeiras 12 horas de vida deve-se ao aumento da secreção de insulina pelo pâncreas fetal exposto a hiperglicemia materna (Teoria de Pedersen). Assinale a alternativa correta.', options: ['Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente as afirmativas 2 e 5 são verdadeiras.', 'Somente as afirmativas 1, 2 e 4 são verdadeiras.', 'Somente as afirmativas 3, 4 e 5 são verdadeiras.', 'As afirmativas 1, 2, 3, 4 e 5 são verdadeiras.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_045', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'A restrição de crescimento fetal (RCF) representa hoje uma patologia de relevância na prática clínica do obstetra. Sabe-se que atualmente o diagnóstico acurado, tal como o manejo criterioso desses fetos, é imprescindível para o desfecho perinatal adequado. Com relação à RCF, assinale a alternativa INCORRETA.', options: ['A mortalidade do feto com restrição de crescimento é cerca de oito vezes maior quando comparada ao feto com peso adequado para a idade gestacional.', 'O recém-nascido acometido pela RCF tem maior risco de insuficiência respiratória, hipoglicemia, hipocalemia, hipotermia e prejuízo no desenvolvimento neuropsicomotor.', 'O estudo Doppler é um método que auxilia na distinção do feto pequeno para a idade gestacional constitucional daquele feto pequeno por insuficiência placentária.', 'Estudos recentes indicam que o risco de resultado perinatal adverso em casos de RCF tardia pode ser melhor avaliado pelo Doppler cerebral, visto que o Doppler da artéria umbilical pode não se modificar.', 'Em casos de insuficiência placentária prolongada, evoluindo com vasoconstrição periférica fetal intensa, observa-se a deterioração da função cardíaca que pode ser avaliada pelo Doppler do ducto arterioso.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_046', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'MIS, 36 anos, G3C3, comparece à unidade de saúde para orientações contraceptivas. Realizou seguimento de pré-natal em UBS, sem nenhuma intercorrência na gestação. Não apresenta nenhuma comorbidade e não faz uso de medicações periodicamente. Apresentou boa evolução durante o período de internação e recebeu alta hospitalar após completadas as 48 horas de puerpério. Encontra-se, hoje, no 50º dia pós-parto e em aleitamento materno exclusivo. Assinale a alternativa com a orientação contraceptiva adequada a essa paciente.', options: ['Dos métodos hormonais disponibilizados pela unidade de saúde, recomenda-se à paciente usar a minipílula e o injetável trimestral.', 'A paciente deverá ser informada sobre o método de lactação e amenorreia e, caso opte pelo uso de contracepção intrauterina, apenas o DIU de cobre poderá ser indicado.', 'A paciente deverá ser informada sobre os métodos intrauterinos (DIU de cobre e SIU liberador de levonorgestrel), mas, caso opte por algum desses métodos, deverá aguardar a menstruação para inserção.', 'A paciente deverá ser desencorajada a usar métodos farmacológicos, para evitar qualquer influência na amamentação.', 'A paciente não poderá fazer uso de contraceptivos orais, pelo risco de trombose e de influência na amamentação.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_047', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Sobre o ciclo menstrual humano, é INCORRETO afirmar:', options: ['A reserva ovariana é determinada ao nascimento e sofre queda constante, mesmo durante períodos fisiológicos de anovulação, como na infância e na gravidez.', 'O desenvolvimento folicular ovariano é dependente de níveis basais de androgênios.', 'A segunda divisão meiótica do oócito é completada antes da ovulação, sob efeito do hormônio luteinizante (LH).', 'A esteroidogênese ovariana consiste em um processo de ação conjunta das células da teca e da granulosa, com ação combinada de LH e FSH.', 'Os níveis de inibina atingem o ponto máximo no meio da fase lútea e diminuem caso não haja gravidez, permitindo nova elevação do hormônio folículo estimulante (FSH).'], correctIndex: 2 },
  { id: 'ufpr_2019_101_048', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'CGL, 39 anos, é casada há 12 anos. Nunca usou nenhum método contraceptivo. Informa que deseja ter filhos e há 6 meses iniciou tentativas de engravidar. Está muito ansiosa com a demora e procura atendimento. Ela é nuligesta. Refere ter uma boa vida sexual. Os ciclos menstruais são longos e irregulares (chegam a durar 50 dias), com fluxo normal e sem dismenorreia. Não apresenta nenhuma outra queixa. Exame tocoginecológico normal. Sobre a condução desse caso, assinale a alternativa correta.', options: ['A paciente deverá ser orientada a continuar com relações sexuais frequentes, uma vez que seu tempo de tentativa ainda é pequeno para necessitar investigação.', 'Pode-se fazer o diagnóstico de infertilidade primária e, devido à idade da paciente, já deve ser encaminhada para fertilização in vitro.', 'Por apresentar ciclos longos, a causa de infertilidade é provavelmente a anovulação e a paciente deverá receber prescrição de drogas para induzir a ovulação, como clomifeno ou letrozol.', 'Deve-se solicitar os exames para avaliação hormonal, dos fatores tubáreo e masculino, antes de indicar algum tipo de abordagem.', 'A infertilidade é de causa primária masculina e os exames para avaliar o fator tubário são dispensáveis.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_049', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Paciente com 25 anos vem à consulta com queixa de dor em baixo ventre associada à cefaleia, náuseas e dor lombar, e em membros inferiores há cerca de 24 horas, podendo estar associada com dismenorreia. Em relação a esse caso, assinale a alternativa INCORRETA.', options: ['O uso do sistema intrauterino de levonorgestrel tem ação no controle da dor principalmente nos casos associados com endometriose.', 'Cerca de 10 a 20% dos casos de dismenorreia não respondem ao tratamento com anti-inflamatórios não hormonais ou anticoncepcionais orais.', 'A neurectomia pré-sacral foi demonstrada como eficaz nessa situação.', 'O uso de anticoncepcionais orais combinados com anti-inflamatórios não hormonais tem lugar para os casos refratários.', 'Os análogos do GnRH, embora tenham ação nesse quadro, não são utilizados na prática devido aos seus efeitos colaterais de hipoetrogenismo muito intenso.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_050', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'A bexiga hiperativa é uma síndrome que se caracteriza pela urgência miccional usualmente acompanhada de aumento da frequência urinária e de noctúria na ausência de fatores infecciosos, metabólicos ou locais. Em relação à fisiopatologia da bexiga hiperativa, é correto afirmar:', options: ['O modelo neurogênico (teoria neurogênica) determina que os sintomas de urgência e o aumento da frequência miccional estão associados com denervação e ligações intercelulares anormais.', 'Na teoria miogênica, a hipoatividade vesical associada à hipertrofia das células musculares do detrussor explicariam o quadro clínico.', 'As alterações do microbioma vesical e a severidade dos sintomas se associam com a fisiopatologia da bexiga hiperativa.', 'A cura da urgeincontinência e da incontinência urinária de esforço podem ser realizadas por cirurgia.', 'O óxido nítrico, liberado por nervos eferentes do colo vesical e da uretra, está envolvido no mecanismo de contração vesical e uretral e influencia a síndrome.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_051', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Paciente com 19 anos de idade e exame citológico compatível com lesão intraepitelial escamosa de alto grau (HSIL). No exame colposcópico, foi visualizado extensa placa ectocervical de epitélio branco em lábio superior e inferior do colo uterino, que corresponde a um achado maior pela Classificação da IFCPC-Rio 2011. Essa lesão é totalmente visualizada tanto em seu limite caudal como no cranial. Nesse caso, a melhor conduta é:', options: ['repetir o exame citológico imediatamente.', 'indicar o método Ver X Tratar.', 'solicitar a volta da paciente em 6 meses para nova citologia.', 'solicitar a volta da paciente em 6 meses para a coleta do teste de DNA-HPV.', 'realizar biópsia da área correspondente ao epitélio branco.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_052', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Paciente, com 55 anos de idade, vem à consulta relatando como queixa principal sensação de "bola na vagina". No exame ginecológico, foi constatada a presença de prolapso uterino de grau IV na classificação de Baden-Walker. Com relação à conduta nesse caso, assinale a alternativa correta.', options: ['O uso do estrogênio tópico está indicado nesse caso como terapêutica definitiva.', 'O procedimento reconstrutivo é a primeira linha de tratamento em relação ao obliterativo.', 'O tratamento expectante deverá ser priorizado em relação ao procedimento obliterativo.', 'Após a correção cirúrgica do prolapso, indica-se o uso de estrogênio tópico e exercícios vaginais.', 'A histerectomia vaginal é o tratamento de eleição para a correção do prolapso quando existe a concomitância de descenso do colo do útero.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_053', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Paciente de 23 anos, sexarca aos 18 anos, com um parceiro sexual, utiliza anticoncepcional hormonal oral. Refere último coito há 2 semanas. Vem à consulta no Pronto Atendimento de Ginecologia queixando-se de corrimento amarelo, fétido, às vezes esverdeado, em média quantidade, tendo iniciado há 2 dias. Nuligesta, nega comorbidades. Ao exame ginecológico: edema e hiperemia vulvar discreta, vagina com hiperemia difusa, conteúdo vaginal amarelo-esverdeado e colo com hiperemia. Junção escamo colunar -2. Qual a impressão diagnóstica e a conduta, respectivamente?', options: ['Chlamydia Trachomatis – azitromicina 1 grama via oral, dose única.', 'Gardnerella Vaginalis – metronidazol 250 mg dois comprimidos via oral de 8 em 8 horas por 7 dias.', 'Trichomonas Vaginalis – metronidazol 250 mg dois comprimidos via oral de 12 em 12 horas por 7 dias.', 'Candidiase vaginal – fluconazol 150 mg, dose única.', 'Neiserria Gonorrhoeae – ceftriaxona 500 mg Intramuscular, dose única.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_054', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Paciente de 26 anos, G3P1A2 (fez 2 curetagens uterinas evacuadoras, a última há 11 meses). Procura Unidade Básica de Saúde queixando-se de falta de menstruação, quadro esse iniciado há 9 meses. Não faz anticoncepção e nega uso de outros medicamentos. Paciente deseja engravidar. Refere telarca aos 11 anos e menarca aos 13 anos. Antecedentes menstruais: ciclos menstruais regulares pós-menarca. Antecedentes pessoais: nega cirurgia, etilismo e tabagismo. Fez 3 exames do Beta HCG que foram todos negativos, sendo o último há 10 dias. Traz os seguintes exames realizados há 1 semana: FSH 8 mUI/mL, prolactina 10 ng/mL, TSH 2,5 mUI/mL, T4 livre 1,2 ng/dL, testosterona total 60 ng/dL. Peso: 62 kg, altura 1,58 m. IMC: 24,89. Exame físico: sem alterações. Exame ginecológico: mamas sem alterações. Órgãos genitais externos (OGE): pilificação normal para sexo e idade. Formações labiais normais. Especular: conteúdo escasso. Colo epitelizado. Toque: colo cartilaginoso, útero em anteversoflexão (AVF) de tamanho normal. Anexos e paramétrios não palpáveis. Teste do estrogênio + progestogênio foi negativo. Nesse caso, qual a causa da amenorreia secundária, o método terapêutico e a conduta, respectivamente?', options: ['Hipotalâmica (síndrome de Simmonds), teste do GnRH e prescrição de gonadotrofinas.', 'Uterina (síndrome de Asherman), histerossalpingografia e histeroscopia para lise de aderências.', 'Hipofisária (síndrome de Asherman), ressonância magnética da hipófise e prescrição de gonadotrofina de mulher menopausada.', 'Gonadal (síndrome dos ovários policísticos), ecografia pélvica endovaginal e solicitação de LH para ver relação LH/FSH com prescrição de citrato de clomifeno.', 'Vaginal (síndrome de Sheehan), histerossalpingografia e histeroscopia para lise de aderências.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_055', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Paciente de 35 anos, G1P1, teve seu último parto há 2 anos. Não tem parceiro fixo. Está internada na enfermaria de ginecologia devido a um quadro de dor pélvica aguda iniciado há 10 dias, febre 38,6 ºC (referida pela paciente). Refere corrimento fétido. Exame físico: PA 100x70 mmHg, pulso 104 bpm, temperatura axilar 38,5 ºC. Mamas sem alterações. Exame de abdome: dor à palpação na fossa ilíaca esquerda. Especular: conteúdo muco purulento, colo friável, junção escamo colunar -2. Toque: dor à mobilização do colo uterino, sensibilidade aumentada no anexo esquerdo. Exames laboratoriais: VHS 25 mm/H; Hb 10,5; hematócrito 30; leucócitos 11000/mm3. Ecografia pélvica endovaginal: útero em anteversoflexão (AVF) medindo 7x5x7 cm. Volume uterino: 122,5 cm3. Endométrio 9 mm. Massa anexial à esquerda medindo 8x6x5 cm cística com debris no seu interior, conteúdo amorfo. A conduta adequada para esse caso é:', options: ['doxiciclina 100 mg via oral de 12 em 12 horas + metronidazol 500 mg de 8 em 8 horas por 14 dias.', 'doxiciclina 100 mg via oral de 12 em 12 horas + ceftriaxona 500 mg intramuscular por 14 dias.', 'videolaparoscopia para drenagem da massa anexial, doxiciclina 100 mg via oral de 12 em 12 horas + metronidazol 500 mg de 12 em 12 horas + ceftriaxona 500 mg intramuscular, dose única.', 'clindamicina 900 mg por via intravenosa de 8 em 8 horas + gentamicina 3 a 5 mg/kg endovenoso a cada 24 horas, manutenção do tratamento por 48 horas e reavaliação do caso para escalonamento para via oral por 14 dias.', 'ceftriaxona 500 mg Intramuscular a cada 24 horas + metronidazol 500 mg endovenoso a cada 8 horas, manutenção do tratamento por 48 a 72 horas e reavaliação do caso para escalonamento para via oral por 14 dias.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_056', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Paciente de 25 anos vem à consulta de climatério. Nuligesta, casada há 1 ano. Sexarca aos 19 anos. Menarca aos 13 anos. No início, ciclos irregulares, na sequência, ciclos regulares e, mais recentemente, oligomenorreia e amenorreia há 1 ano. Refere fogachos 6 a 8 episódios/dia, secura vaginal e dispareunia. Antecedentes pessoais: nega tabagismo, etilismo, cirurgia e uso de quimioterapia. PA 120x80 mmHg, peso 68 kg, altura 160 cm, IMC: 26,56. Nega uso de qualquer medicamento. Traz 4 exames de BhCG quantitativo, todos negativos, sendo o último há 10 dias. Exame físico: mamas tamanho normal, ausência de nódulos palpáveis, axilas com gânglios impalpáveis. Abdome sem particularidades. Órgãos genitais externos (OGE): pilificação e formações labiais normais. Especular: conteúdo escasso, colo epitelizado. Toque vaginal: colo cartilaginoso, pequeno, corpo uterino em retroversoflexão (RVF) e de tamanho normal. Anexos e paramétrios impalpáveis. Para confirmar o diagnóstico de insuficiência ovariana primária, quais exames devem ser solicitados?', options: ['FSH, estradiol, cariótipo, prolactina, TSH. Caso o FSH > 40 mUI/mL, repetir FSH e estradiol em 4 semanas.', 'Prolactina, TSH, LH, FSH, estradiol. Caso o FSH > 30 mUI/mL, repetir FSH e estradiol em 2 semanas.', 'TSH, estradiol, cariótipo, prolactina, FSH, sulfato de dehidroepiandrosterona (SDHEA), cortisol. Caso o FSH > 30 mIU/mL repetir FSH e estradiol em 6 semanas.', 'FSH, LH, cortisol, SDHEA, estradiol, prolactina, TSH. Caso FSH > 40 mUI/ mL, repetir FSH e estradiol em 4 semanas.', 'Cariótipo, FSH, LH, estradiol, TSH, prolactina, cortisol, insulina basal. Caso FSH > 30 mUI/mL repetir FSH e estradiol em 40 dias.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_057', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Paciente de 28 anos, G2C2, utiliza pílula anticoncepcional como método contraceptivo (contendo etinilestradiol 30 mcg + drospirenona 3 mg). O último parto foi há 2 anos. Está separada do marido. Não tem companheiro fixo. Não usa preservativo. Refere último coito há 30 dias. Vem à consulta ginecológica queixando-se de corrimento claro, pequena quantidade, sem odor fétido. Refere disúria moderada. Exame especular: vulva e vagina sem alterações. Conteúdo vaginal claro, aspecto mucoide. Colo com ectopia e friabilidade com sangramento fácil da mucosa cervical. Toque: colo friável, corpo uterino em anteversoflexão, tamanho normal. Anexos e paramétrios sem alterações. Nesse caso, qual a hipótese diagnóstica, o método diagnóstico e a conduta, respectivamente?', options: ['Cancro mole – bacterioscopia corada pelo Gram e identificação de morfotipos de H. ducreyi – ciprofloxacina 500 mg via oral, de 12 em 12 horas, por 3 dias.', 'Sífilis – VDRL e teste treponêmico – penicilina benzatina 2,4 milhões UI intramuscular (sendo 1,2 milhões UI em cada glúteo), dose única.', 'Neisseria gonorrhoeae – cultura em meio de Thayer-Martin – ceftriaxona 500 mg IM, dose única.', 'Chlamydia Trachomatis – captura híbrida para clamídia – doxiciclina 100 mg via oral, de 12 em 12 horas, por 7 dias.', 'Micoplasma – cultura para micoplasma – metronidazol 2 gramas via oral, dose única.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_058', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Legal', text: 'A coleta e realização de exames laboratoriais, tanto os exames destinados à proteção da vítima quanto os forenses, nos casos de atendimento a mulheres que sofreram violência sexual, preferencialmente nas primeiras 24 horas após violência, têm por finalidade a identificação de doenças infecciosas existentes e uma possível gravidez, e subsidiar a investigação e a identificação do agressor assim como a elaboração de laudos periciais. Sobre o assunto, considere as seguintes afirmativas: 1. A coleta de sangue é para posterior confronto de DNA com o do possível agressor, além de poder-se avaliar a dosagem alcoólica, dosar Beta HCG e pesquisar doenças infecciosas. 2. Deve-se aguardar o resultado dos exames laboratoriais para o uso da medicação profilática, haja visto que o uso empírico causa risco de toxicidade. 3. Os agentes infecciosos a serem pesquisados incluem a coleta de clamídea e gonococo na cavidade vaginal e dos agentes das hepatites B e C, da sífilis e o HIV – vírus da imunodeficiência adquirida – no sangue. 4. As roupas usadas pelas vítimas e que contenham manchas relacionadas à violência ou indicadas pelas vítimas de apresentarem material ejaculado devem ser coletadas mediante autorização especial da paciente ou de seu representante legal e acondicionadas em envelopes de papel, não devendo ser utilizado saco plástico. 5. É fundamental que se oriente a vítima de violência sexual que esses exames forenses podem ser feitos no Instituto Médico Legal (IML), em até 45 dias após ter ocorrido a violência sexual, caso a vítima não queira ser examinada e realizar as coletas no momento da consulta médica. Assinale a alternativa correta.', options: ['Somente as afirmativas 1 e 2 são verdadeiras.', 'Somente as afirmativas 4 e 5 são verdadeiras.', 'Somente as afirmativas 1, 3 e 4 são verdadeiras.', 'Somente as afirmativas 2, 3 e 5 são verdadeiras.', 'As afirmativas 1, 2, 3, 4 e 5 são verdadeiras.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_059', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Legal', text: 'Vítimas de violência sexual devem ser atendidas por médicos devidamente treinados e capacitados para esse atendimento, conforme preconiza o Ministério da Saúde e a Federação Brasileira das Associações de Ginecologia e Obstetrícia (FEBRASGO). Sobre esse tema, considere as seguintes afirmativas: 1. Vítimas de violência sexual podem ser atendidas num hospital ou serviço de pronto atendimento com apresentação prévia de Boletim de Ocorrência ou autorização judicial numa Delegacia da Mulher ou outra existente. 2. Cadeia de custódia representa o registro documental e cronológico sobre o manuseio de uma evidência ou prova, demonstrando seu percurso desde o local onde é recolhida até o tribunal. 3. Mulheres que tiveram uma gravidez resultante de estupro têm direito ao abortamento previsto em lei, desde que autorizado pelo ministério público ou por um juiz. 4. O atendimento à vítima de violência sexual deve ser feito com imparcialidade pelo médico, que deve manter o sigilo profissional e só preencher a ficha de notificação obrigatória, para fins epidemiológicos, com permissão por parte da vítima. 5. A anticoncepção de emergência para oferecer às mulheres vítimas de violência sexual que não estavam usando anticoncepcional eficaz no momento da agressão deve preferencialmente ser feita com o progestagênio levonorgestrel em dose única de 1,5 mg, por via oral, para uso até 72 horas da violência com alta eficácia. Assinale a alternativa correta.', options: ['Somente as afirmativas 1 e 5 são verdadeiras.', 'Somente as afirmativas 2 e 5 são verdadeiras.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3, 4 e 5 são verdadeiras.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_060', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'JBS, 29 anos, G2P1 (natimorto com 28 semanas por pré-eclâmpsia grave há 8 semanas), A1 (com 14 semanas e feto sem anormalidades há 2 anos), procura seu consultório pois apresenta desejo de gravidez e medo de não conseguir um desfecho perinatal favorável à sua próxima gestação. Nega alcoolismo, tabagismo e uso de drogas. Em sua história ginecológica, relata tratamento de doença inflamatória pélvica aos 21 anos. Nega uso de anticoncepção. Exame especular: vulva e vagina normais. Conteúdo vaginal claro, aspecto mucoide. Colo em fenda, epitelizado. Toque: corpo uterino em anteversoflexão, tamanho normal. Anexos e paramétrios sem alterações. Trouxe ecografia feita há 2 dias sem alterações e anticorpos para síndrome antifosfolipídio (SAF) realizados há 5 dias. Com relação ao caso clínico, assinale a alternativa correta.', options: ['A utilização do AAS durante a gestação, em caso de SAF confirmado, deve ser interrompida 2 semanas antes do parto, enquanto que a enoxaparina pode ser mantida até 24 horas antes do parto, sendo que ambos podem ser reintroduzidos de 8 a 12 horas no pós-parto.', 'Anticorpo anticardiolipina (ACL) IgG e IgM dosado por método Elisa é considerado fortemente positivo quando resultado acima de 40 unidades.', 'Em SAF sem evento trombótico prévio, apenas com eventos obstétricos, a profilaxia realizada durante a gestação inclui uso de AAS e enoxaparina em dose terapêutica durante a próxima gestação e 6 semanas no puerpério.', 'A paciente apresenta critério clínico para SAF e caso os exames de anticorpos solicitados se demonstrem alterados, pode-se realizar o diagnóstico de SAF e programar tratamento profilático com AAS e enoxaparina em sua próxima gestação.', 'Em SAF sem evento trombótico prévio, apenas com eventos obstétricos, a profilaxia com AAS e enoxaparina em dose profilática deve ser realizada durante toda a gestação e durante 6 meses no puerpério.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_061', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido é levado à Unidade Básica de Saúde para reavaliação com 7 dias de vida. Nasceu a termo, pesou 3.200 gramas, permaneceu internado em alojamento conjunto, sem intercorrências e teve alta com 48 horas de vida. A mãe tem 16 anos, é primigesta e não apresentou intercorrências durante a gestação. Refere que o recém-nascido "chora bastante e quer mamar o tempo todo". Quando questionada sobre a amamentação, ela refere que oferece um seio para o bebê mamar durante 10 minutos a cada 3 horas e, na mamada seguinte, oferece o outro seio, repetindo o mesmo procedimento. Ao exame, o recém-nascido apresentava-se em bom estado geral, sem anormalidades, pesando 3.000 gramas. Levando em consideração os dados apresentados, corresponde à conduta adequada para o caso:', options: ['prescrever complementação com fórmula láctea após as mamadas ao seio materno.', 'orientar a manter o tempo de mamada, mas diminuir intervalo entre elas, mantendo-as rigorosamente a cada 2 horas, inclusive durante a noite.', 'orientar que o bebê sugue até esvaziar a mama e que a mãe ofereça as duas mamas em cada mamada, favorecendo a oferta de leite posterior.', 'prescrever sulpirida para a mãe, 1 comprido ao dia, para aumentar a produção láctea.', 'orientar o uso de chupeta para diminuir a irritabilidade do bebê e o estresse materno.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_062', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido com 4 dias de vida, sexo feminino, é levada à Unidade de Pronto Atendimento (UPA) por apresentar, há cerca de 12 horas, dificuldade respiratória progressiva e recusa às mamadas, com piora importante nas últimas 2 horas. Mãe refere gestação sem intercorrências, sorologias negativas e triagem negativa para GBS. O parto foi vaginal, com bolsa rota no ato, com 39 semanas de idade gestacional. O bebê pesou 3.500 gramas e apresentou escore de Apgar de 9/10. Permaneceu em alojamento conjunto, sem intercorrências clínicas e teve alta com 48 horas de vida, após realizar o teste do pezinho (a mãe refere que não sabe se os testes do coraçãozinho, olhinho e orelhinha foram realizados). Ao exame, apresentava-se em mau estado geral, palidez acinzentada, taquidispneico, frequência cardíaca = 200 bpm, frequência respiratória = 80 ipm, sem sopros à ausculta cardíaca, pulsos periféricos reduzidos nos 4 membros, perfusão periférica > 5 segundos. O provável diagnóstico para esse caso é:', options: ['sepse neonatal.', 'hemorragia adrenal bilateral.', 'galactosemia.', 'doença hemorrágica do recém-nascido.', 'síndrome do coração esquerdo hipoplásico.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_063', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'S.S.M., feminina, 39 anos, recebe diagnóstico de tuberculose pulmonar bacilífera e é orientada a trazer todos os comunicantes domiciliares para avaliação. De acordo com o novo Manual de Recomendações para o Controle da Tuberculose do Ministério da Saúde do Brasil (2018), assinale a alternativa que apresenta o caso, o resultado da prova tuberculínica (PT) e a conduta corretos.', options: ['Filha de 15 anos, PT de 15 mm: iniciar isoniazida.', 'Filho de 7 anos, PT de 3 mm, assintomático: acompanhamento clínico.', 'Filha de 4 anos, com tosse há 3 semanas, PT de 22 mm: iniciar rifampicina, isoniazida e pirazinamida.', 'Filha de 1 ano, assintomática, radiografia de tórax normal, PT de 7 mm: iniciar rifampicina.', 'Filho de 7 dias de vida, assintomático: suspender amamentação, não vacinar e iniciar isoniazida.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_064', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'A respeito das meningites, considere as seguintes afirmativas: 1. No Brasil, o principal agente etiológico é o Streptococcus pneumoniae (pneumococo). 2. São doenças altamente contagiosas, transmitidas por aerossóis. 3. O bloqueio do contágio é indicado para os contactantes próximos de casos de meningite meningocócica ou por hemófilos. 4. Todas as meningites são de notificação obrigatória. Assinale a alternativa correta.', options: ['Somente a afirmativa 4 é verdadeira.', 'Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente as afirmativas 2 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2 e 3 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_065', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Sobre as principais características e recomendações na vacinação, é correto afirmar:', options: ['Quando realizada a BCG, aguarda-se até 6 meses para o aparecimento da cicatriz vacinal e, caso não apareça, recomenda-se a realização de uma segunda dose.', 'A toxina diftérica é o componente responsável pela crise hipotônica hiporresponsiva associada à vacina Penta Brasil.', 'A vacina de influenza é indicada a partir dos 6 meses de vida, devendo ser realizada em duas doses na primovacinação até os 9 anos de idade e, depois, repetida anualmente.', 'A vacina de febre amarela é composta por vírus inativado e pode ser realizada a partir de 9 meses de idade.', 'A vacina de sarampo, em situações especiais como em surtos, pode ser realizada a partir de 9 meses de idade.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_066', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'As verrugas virais são infecções causadas pelo papiloma vírus humano (HPV) e são comuns nas crianças. Sobre essas infecções, assinale a alternativa correta.', options: ['As verrugas plantares são pouco dolorosas e respondem rapidamente ao tratamento.', 'As verrugas na região perianal em crianças abaixo de 1 ano ocorrem exclusivamente por transmissão sexual e tornam obrigatórias a investigação de abuso.', 'As verrugas planas, comuns na criança, são grandes e ocorrem principalmente no tronco.', 'Nas verrugas periungueais, as complicações como inflamação e infecção são infrequentes.', 'No tratamento das verrugas em crianças, preferem-se os medicamentos de uso tópico por serem menos agressivos.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_067', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'A região do períneo nos lactentes é frequentemente acometida por doenças cutâneas com diferentes etiologias. Para o diagnóstico correto e instituição do tratamento adequado, é necessário realizar a anamnese completa e exame físico detalhado. Sobre esse tema, considere as seguintes afirmativas: 1. Na dermatite da área de fraldas por irritante primário, as áreas convexas do períneo são acometidas com lesões eritematosas. 2. Na candidíase perineal, o eritema é intenso, as pregas inguinais são poupadas e a ausência de pápulas satélites caracterizam o diagnóstico. 3. Na dermatite de fraldas por irritante primário, os antibióticos tópicos estão indicados, assim como o aumento da frequência de trocas. 4. Na dermatite seborreica, as lesões ocorrem nos lactentes, acometem as pregas inguinais e axilares, além do couro cabeludo. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 1 e 4 são verdadeiras.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 2, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_068', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'B. G., 8 anos de idade, é atendido na emergência com quadro de paralisia flácida aguda de membros inferiores. Ao exame, apresenta nível sensitivo comprometido, táctil, térmico e dor (nível T10), transtorno esfincteriano, ausência de reflexos profundos e sinal de Babinski bilateral. Considerando os dados apresentados, assinale a alternativa que apresenta a localização da lesão.', options: ['Medula.', 'Músculo.', 'Junção mioneural.', 'Nervo periférico.', 'Feixe espinotalâmico no tronco cerebral.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_069', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Menina com 3 anos de idade é levada à consulta médica por apresentar movimentos caracterizados por adução das coxas, sentar-se sobre uma mão ou pé, fazendo um balanço da pelve. Associam-se grunhidos, diaforese e ruborização facial. A duração dos episódios varia de 1 minuto a várias horas. A consciência é mantida e as manifestações cessam com distração ou engajamento em outra atividade. O exame neurológico é normal. Considerando os dados apresentados, a conduta adequada para o caso é:', options: ['indicar exame com videoeletroencefalograma para afastar crise epiléptica.', 'solicitar avaliação gastroenterológica a fim de descartar refluxo gastroesofágico.', 'solicitar avaliação e atendimento psicológico e acompanhamento psiquiátrico.', 'orientar e tranquilizar os familiares, esclarecer que não há necessidade de exames complementares.', 'indicar atendimento psicológico devido ao diagnóstico de transtorno obsessivo compulsivo da infância.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_070', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'A asma é uma doença heterogênea, caracterizada por inflamação das vias aéreas. O paciente apresenta sintomas como sibilância, dificuldade para respirar e tosse e os sintomas apresentam variabilidade com o tempo, com exacerbações e períodos de melhora. O tratamento consiste no uso de corticoides inalatórios, broncodilatadores de ação longa, antagonistas de leucotrienos, entre outros. Algumas características são fatores de risco para exacerbação de asma e devem ser consideradas durante o tratamento. São todos fatores de risco para exacerbação da asma, mesmo em pacientes com poucos sintomas:', options: ['ausência de resposta a broncodilatadores, exposição a tabaco, obesidade e crise grave nos últimos 2 anos.', 'exposição a alérgenos se sensibilizado, internação em UTI por asma, espirometria sem reversibilidade a broncodilatadores e elevados níveis de IgE.', 'uso de corticoide inalatório de alta potência em doses altas, presença de eosinófilos no escarro, necessidade de corticoide oral nas exacerbações e presença de alergia alimentar.', 'obesidade, eosinofilia no hemograma, níveis elevados de IgE e espirometria com valores baixos sem resposta ao uso de broncodilatadores.', 'adesão regular ao tratamento, uso infrequente de medicação de resgate, resposta broncodilatadora na espirometria e hemograma com neutrofilia.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_071', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Criança vem à consulta acompanhada de sua mãe, com história de episódios de chiado. Nos últimos 12 meses, apresentou 5 episódios de "chio no peito," com dificuldade para respirar, e a mãe acha que a criança apresentou melhora depois de um dia de tratamento com broncodilatador. Entre os episódios de chiado, a criança fica bem, porém apresenta tosse quase diária, às vezes associada a vômitos, mas com pouca interferência nas atividades como brincar e dormir. Além disso, a mãe relata que a criança tem o nariz congestionado desde o nascimento e teve asma até os 4 anos de idade. A criança nasceu a termo, pesou 3.300 gramas e apresentou desconforto respiratório no período neonatal, necessitando de internação em UTI Neonatal, sem necessidade de internação em outras ocasiões. Ao exame físico: peso = 14 kg; estatura = 86 cm; frequência respiratória = 40 ipm; frequência cardíaca = 108 bpm; Sat.O2 = 98%. Chama atenção a presença de deformidade do tórax; observou-se tiragem intercostal e supraclavicular, sem estertores, sibilos expiratórios e baqueteamento digital. Levando em consideração os dados apresentados, é correto afirmar:', options: ['O paciente apresenta dados clínicos compatíveis com asma e deve iniciar tratamento com corticoide inalatório.', 'As manifestações clínicas apresentadas são compatíveis com discinesia ciliar, mas há necessidade de exames complementares para confirmar o diagnóstico, como estudo genético.', 'A presença de baqueteamento digital com oximetria de pulso normal é um achado de exame físico sem relevância clínica no caso apresentado.', 'O diagnóstico de alergia alimentar com refluxo gastroesofágico deve ser considerado e investigado por meio de seriografia esôfago gastroduodenal.', 'A presença de sibilos, esforço respiratório e dificuldade para respirar sugere quadro de bronquiolite viral recorrente em pacientes nessa idade e o tratamento recomendado é seguimento clínico.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_072', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Paciente de 10 anos, masculino, apresenta quadro de dor abdominal há 6 meses. A dor é periumbilical e mal definida, e ocorre sem irradiação, no final da tarde, quase diariamente. O paciente nega relação com alimentação. Não há fatores de piora ou melhora. O paciente não apresenta febre, diminuição de peso e nega perda de apetite ou vômitos; tem evacuação diária e as fezes apresentam consistência normal. A dor não melhora com as evacuações. Não apresenta outros sintomas. Exame físico normal, incluindo toque retal. Em relação ao caso apresentado, considere as seguintes afirmativas: 1. Para esclarecimento do diagnóstico, está indicada a realização de uma radiografia simples de abdome. 2. A prescrição de amitriptilina é indicada. 3. Uma colonoscopia com biópsia de íleo terminal está indicada para descartar doença de Crohn. 4. Para abordagem correta do diagnóstico, é importante investigar o perfil psicossocial, incluindo relacionamento e dificuldades familiares ou com amigos, mudança de escola ou endereço e dificuldades na escola. Assinale a alternativa correta.', options: ['Somente a afirmativa 4 é verdadeira.', 'Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente as afirmativas 2 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2 e 3 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_073', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Paciente de 12 anos, masculino, apresenta há 3 anos fezes amolecidas, 3 a 4 vezes ao dia, distensão abdominal e flatulência. De 1 a 2 vezes ao mês apresenta vômitos. Nega febre, dor abdominal, diminuição de apetite ou perda de peso. Apresenta curva de crescimento adequada. Fez uso de albendazol por 5 dias sem melhora. Levando em consideração os dados apresentados, o diagnóstico diferencial inclui:', options: ['retocolite ulcerativa e o paciente deve ser submetido inicialmente à colonoscopia com biópsias.', 'doença celíaca e o paciente deve ser submetido inicialmente à endoscopia digestiva alta com biópsias.', 'giardíase e o paciente deve ser tratado inicialmente com mebendazol.', 'intolerância à lactose primária e o paciente deve fazer inicialmente uma prova terapêutica com dieta sem lactose por 2 semanas.', 'intolerância à lactose secundária e o paciente deve fazer inicialmente o teste genético para intolerância à lactose.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_074', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente de 3 meses de vida é levado ao pediatra por palidez e dificuldade para mamar. O paciente não apresenta febre, alterações respiratórias, urinárias ou gastrointestinais, além de não ter história de sangramento. Aleitamento materno exclusivo. Mãe foi submetida à cirurgia bariátrica há 2 anos. Ao exame físico, a criança apresentava palidez, auscultas pulmonar e cardíaca normais, ausência de visceromegalias, ausência de linfonodomegalias, sem lesões de pele. Resultados de exames laboratoriais: hemograma com hemoglobina 7,5 g/dL, hematócrito 22%, VCM 118 fl, leucócitos 2.100/mm3(linfócitos 1.500/mm3, segmentados 400/mm3, monócitos 150/mm3, eosinófilos 50/mm3), plaquetas 55.000/mm3; valor de reticulócitos normal. Com base nas informações acima, a principal hipótese diagnóstica nesse caso é:', options: ['esferocitose.', 'beta-talassemia major.', 'trombocitopenia primária imune.', 'anemia ferropriva.', 'deficiência de vitamina B12.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_075', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Menina de 5 anos é levada ao pronto atendimento por aumento de volume abdominal progressivo com dor há 2 semanas. Não apresenta febre, alterações urinárias ou gastrointestinais. Ao exame físico, além de massa palpável em hipocôndrio esquerdo, a paciente apresentava pilificação pubiana, hipertrofia de clitóris e acne. Mãe relata que percebeu essas alterações há aproximadamente 6 meses, mas achou que fazia parte do desenvolvimento da criança. Levando em consideração os dados apresentados, a principal hipótese diagnóstica e os exames laboratoriais que devem ser solicitados para o esclarecimento diagnóstico são, respectivamente:', options: ['neuroblastoma – ferritina, desidrogenase láctica e ácido vanilmandélico.', 'puberdade precoce – hormônio luteinizante (LH), hormônio folículo estimulante (FSH) e estradiol.', 'carcinoma de suprarrenal – sulfato de dehidroepiandrosterona (DHEA-S), cortisol e testosterona total.', 'tumor de células germinativas – alfafetoproteína e gonadotrofina coriônica humana (BetaHCG).', 'hiperplasia congênita de suprarrenal forma virilizante simples – 17-hidroxi-progesterona (17-OHP), cortisol e testosterona total.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_076', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Levando em consideração a etiologia e a fisiopatologia dos distúrbios do crescimento, assinale a alternativa correta.', options: ['Adenomas hipofisários são os tumores que mais comumente causam deficiência de GH em crianças.', 'A deficiência combinada de hormônios hipofisários pode ser de causa genética.', 'Hipertireoidismo, hipoparatireoidismo e raquitismo são causas de baixa estatura.', 'Doença de Cushing causa aceleração do crescimento e virilização em crianças e adolescentes.', 'Hiperglicemia pode ser decorrente da síndrome de Cushing e da deficiência de GH na infância.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_077', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Em relação à triagem neonatal biológica no Brasil, assinale a alternativa correta.', options: ['A coleta do teste antes de 48 horas de vida pode ocasionar em resultado falso positivo para hipotireoidismo congênito e falso negativo para fenilcetonúria.', 'A idade ideal da coleta é entre o 5º e o 7º dia de vida, devendo ser repetida se o recém-nascido prematuro com 30 dias de vida.', 'Recém-nascidos prematuros devem ter a coleta de sangue realizada somente quando completarem 40 semanas de idade gestacional corrigida.', 'O Programa Nacional de Triagem Neonatal preconiza que é obrigatória a pesquisa de fenilcetonúria, hipotireoidismo congênito e hemoglobinopatias; a pesquisa de outras doenças fica a critério do serviço de referência em triagem neonatal de cada estado.', 'A maior parte das crianças com hipotireoidismo congênito diagnosticada pela triagem neonatal não tem manifestações clínicas e por isso o tratamento pode ser postergado até um mês de vida.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_078', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Segundo GINA 2019 (Global Initiative for Asthma), qual alternativa contempla somente critérios de crise aguda de asma grave ou severa em crianças abaixo de 5 anos?', options: ['Agitação, saturação de O2 < 94%, tórax silencioso e inabilidade em falar frases.', 'Agitação, saturação de O2 < 92%, diminuição de murmúrio vesicular em bases e inabilidade em falar palavras.', 'Confusão e/ou agitação, saturação de O2 < 90%, tórax silencioso e inabilidade em falar frases.', 'Irritabilidade, frequência cardíaca >220 batimentos por minuto, saturação de O2 < 94% e inabilidade em falar frases.', 'Confusão e/ou agitação, saturação de O2 < 92%, tórax silencioso e inabilidade em falar palavras.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_079', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Em relação à pneumonia adquirida na comunidade (PAC) em crianças, considere as seguintes afirmativas: 1. É a principal causa de morte não externa em crianças em países em desenvolvimento. 2. Em crianças abaixo de 2 meses, frequência respiratória acima de 60 incursões respiratórias por minuto e tiragem subcostal são sinais de pneumonia muito grave, sendo obrigatória a internação. 3. Os vírus são responsáveis pela maioria das PAC, sendo responsáveis por cerca de 90% das pneumonias em crianças ˂ 1 ano e de 50% em escolares. 4. A radiografia de tórax deve ser realizada de rotina para o diagnóstico PAC em crianças, com ou sem necessidade de tratamento hospitalar, uma vez que há evidências que modifica a evolução clínica e a conduta. Assinale a alternativa correta.', options: ['Somente a afirmativa 2 é verdadeira.', 'Somente as afirmativas 1 e 4 são verdadeiras.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2 e 3 são verdadeiras.', 'As afirmativas 1, 2, 3, e 4 são verdadeiras.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_080', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Criança de 8 anos é admitida na UTI Pediátrica por insuficiência respiratória. Após entubação endotraqueal e início da ventilação mecânica, foi coletada a gasometria arterial, que apresentou o seguinte resultado: pH 7,34, pCO2 74 mmHg, pO2 94 mmHg, bicarbonato 32 mEq/L, BE +8, saturação 93%. Levando em consideração os dados apresentados, o que se evidencia nessa gasometria arterial?', options: ['Acidose metabólica grave.', 'Acidose respiratória crônica.', 'Acidose metabólica compensada.', 'Alcalose respiratória.', 'A gasometria é normal.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_081', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'A respeito do diagnóstico laboratorial do HIV, considere as seguintes afirmativas: 1. A reatividade cruzada de anticorpos pode ser observada em algumas amostras em virtude de várias doenças autoimunes, podendo produzir resultados falso-reagentes nos ensaios imunológicos. 2. Após a transmissão do vírus, ocorre a fase de eclipse, que corresponde ao período de replicação local do patógeno e em que o RNA viral é detectável no plasma. 3. No paciente HIV+, a presença da IgM não permite diferenciar uma infecção recente de uma infecção crônica, tendo em vista que a IgM pode reaparecer em outros momentos durante o curso da infecção. 4. Os testes complementares convencionais, como western blot e imunoblot rápido, são menos sensíveis que os imunoensaios de 3a e 4a gerações, podendo produzir resultados falso não reagentes. Assinale a alternativa correta.', options: ['As afirmativas 1, 2, 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 3 e 4 são verdadeiras.', 'Somente as afirmativas 2 e 4 são verdadeiras.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente a afirmativa 1 é verdadeira.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_082', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Referente aos aspectos epidemiológicos das micoses sistêmicas, considere as afirmativas abaixo: 1. A maioria dos casos de esporotricose atualmente observados no Brasil são de transmissão felina. 2. A histoplasmose é causada por um fungo dimórfico que se desenvolve em solo contaminado com fezes de morcego e de aves como galináceos. 3. A paracoccidioidomicose acomete principalmente mulheres que trabalham na lavoura. 4. A maioria dos casos de paracoccidioidomicose crônica são tratados com itraconazol. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_083', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Sobre prevenção de novas infecções pelo HIV, assinale a alternativa correta.', options: ['A carga viral-HIV materna suprimida (carga viral plasmática abaixo de 50 cópias/mL) no início da gestação (antes de 14 semanas) é o fator determinante na queda do risco de transmissão materno-fetal do HIV.', 'No uso da PEP (prevenção pós-exposição), o primeiro atendimento deve ser considerado uma urgência e a terapia deve ser iniciada o mais breve possível, sendo 96 horas subsequentes à exposição o limite para o início do tratamento.', 'O acesso à terapia antirretroviral é importante na redução da transmissão, mesmo havendo escassos relatos na literatura comprovando a transmissão do HIV por pessoa em supressão viral.', 'Não existe correlação linear entre níveis de adesão e eficácia da prevenção pré-exposição (PrEP), conforme ensaios clínicos realizados envolvendo diferentes segmentos populacionais.', 'A adesão subótima ao tratamento do paciente cronicamente infectado pode levar à presença de carga viral plasmática do HIV, o que não só prejudica o paciente, mas também aumenta o seu risco de transmissão sexual.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_084', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Legal', text: 'LSF, 89 anos, feminina, encontrava-se há 1 mês internada na Unidade de Terapia Intensiva com diagnóstico de sangramento intracraniano, traumatismo cranioencefálico e coma. No 31º dia de internamento após acidente por atropelamento, evoluiu para óbito por quadro de septicemia decorrente de infecção pulmonar por germe hospitalar. Encontrava-se em ventilação mecânica, tendo desenvolvido a broncopneumonia após cirurgia descompressiva por hemorragia intracraniana. Em relação aos cuidados a serem adotados no preenchimento da Declaração de Óbito (DO), considere as seguintes afirmativas: 1. A DO deverá ser preenchida pelo neurocirurgião que realizou o procedimento cirúrgico. 2. A DO deverá ser preenchida pelo médico legista. 3. A causa terminal da morte deverá ser informada como septicemia. 4. A causa básica da morte deverá ser informada como infecção hospitalar. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_085', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Qual o método epidemiológico de escolha para a investigação da história natural de uma doença e de seus fatores prognósticos?', options: ['Estudo de intervenção terapêutico.', 'Ensaio clínico preventivo.', 'Estudo de caso-controle.', 'Estudo de coorte.', 'Estudo de prevalência.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_086', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Primaquina é a única droga usada para a prevenção de recaídas da malária por Plasmodium vivax (P. vivax), mas a adesão ao esquema de 14 dias é baixa. Estudo randomizado, duplo-cego, controlado por placebo, multicêntrico, de não inferioridade, foi efetuado para avaliar a eficácia da primaquina no esquema curto (7 dias) em relação ao esquema longo (14 dias) para a cura, sem recaída, da malária por P. vivax. Todos os pacientes receberam esquizonticidas e foram alocados aleatoriamente em 3 grupos, segundo o uso ou não de primaquima: 1. primaquina 7 dias (n=935), 2. primaquina 14 dias (n=937) e 3. placebo (n=464). Resultados de recaída até 12 meses: primaquina 7 dias vs controle HR=0,17 (0,12–0,23), p<0,0001; primaquina 14 dias vs controle HR=0,14 (0,09–0,21), p<0,0001; primaquina 7 dias vs 14 dias HR=1,17 (0,88–1,55), p=0,28. Levando em consideração os dados apresentados, assinale a alternativa correta.', options: ['Os tratamentos têm eficácias baixas, menores de 50%.', 'Não há diferença significativa dos resultados entre os três grupos.', 'O tratamento com esquema curto (7 dias) tem eficácia semelhante ao longo (14 dias).', 'Como o valor de p não foi menor que 0,05 em todos os cruzamentos, não há esquema de tratamento.', 'O número de pacientes com malária por P. vivax que precisam ser tratados para se evitar uma recaída é o inverso da diferença dos HRs, (NNT= 1/0,17-0,14).'], correctIndex: 2 },
  { id: 'ufpr_2019_101_087', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Um médico psiquiatra, ao ler artigo em que são avaliados critérios diagnósticos de esquizofrenia, comenta que esses critérios mostraram uma sensibilidade de 60% e especificidade de 90% no estudo ao confrontar com o diagnóstico da doença a longo prazo, concluindo que os pacientes com resultado negativo têm uma probabilidade alta de não terem o problema e que, portanto, daria para descartar esse diagnóstico. Levando em consideração os dados apresentados, a conclusão do psiquiatra:', options: ['pode estar correta dependendo do cálculo da acurácia desses critérios.', 'é correta pois existe uma alta especificidade (90%).', 'é incorreta porque é preciso ter informações sobre o Valor Preditivo Positivo apresentado no estudo.', 'pode estar correta se existir uma alta frequência de doentes entre os pacientes avaliados.', 'pode estar correta caso o Valor Preditivo Negativo no estudo seja alto.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_088', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Sabendo-se que a vigilância dos casos e a vacinação são medidas essenciais para o controle do sarampo, considere as seguintes afirmativas: 1. Casos de sarampo devem ter notificação obrigatória semanal, permitindo o bloqueio vacinal de contatos não vacinados. 2. A notificação do sarampo deve ser feita para casos suspeitos. 3. O esquema de vacinação para proteção contra o sarampo na infância é de uma dose da vacina tríplice viral aos 12 meses e uma dose da vacina tetraviral aos quatro anos. 4. Adolescentes e adultos devem ter na vida duas doses com os componentes da vacina tríplice viral até os 29 anos e uma dose entre 30 a 49 anos, sendo que acima de 49 anos não há indicação na rotina. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente as afirmativas 2 e 4 são verdadeiras.', 'Somente as afirmativas 2, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_089', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Quanto aos estudos epidemiológicos e medidas de associação e impacto, considere as seguintes afirmativas: 1. Nos estudos ecológicos, a unidade de análise é representada por grupos populacionais, sendo que a relação entre exposição e efeito no nível individual não pode ser estabelecida. 2. Intervenções com número necessário para tratar (NNT) elevado têm impacto muito maior em relação às que apresentam NNT com valores baixos. 3. Uma das vantagens dos estudos de coorte é que eles permitem a avaliação do risco relativo de um fator de exposição para diversos desfechos. 4. Ao realizar um estudo para avaliar a incidência de câncer de bexiga em trabalhadores de uma determinada empresa, o pesquisador fará uma modalidade de estudo denominada transversal. Assinale a alternativa correta.', options: ['Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente as afirmativas 2 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2 e 3 são verdadeiras.', 'Somente as afirmativas 2, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_090', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Levando em consideração a NR 32, de 2005, atualizada pela Portaria GM nº 1748, de agosto de 2011, do então Ministério do Trabalho e Emprego, e o conhecimento técnico sobre radiações ionizantes, assinale a alternativa correta.', options: ['Os estabelecimentos de saúde com setor de radiodiagnóstico médico devem elaborar um Programa de Proteção Respiratória (PPR) por ser o sistema respiratório o principal sistema acometido durante a exposição à radiação ionizante.', 'Os trabalhadores que realizam atividades em áreas onde existem fontes de radiações ionizantes devem ser submetidos à monitoração anualmente, mediante dosimetria individual.', 'A proteção radiológica dos trabalhadores expostos às radiações ionizantes está baseada em três princípios básicos de radioproteção, que são: tempo de exposição; distância da fonte e conhecimento técnico dos trabalhadores sobre radiações.', 'As salas de raios X dos serviços de radiodiagnóstico médico ficam contaminadas com radiações ionizantes de forma que o auxiliar de serviços gerais que realiza a limpeza da sala possui exposição a essas radiações e deve ser monitorado quanto à exposição ocupacional à radiação.', 'Em relação ao poder de penetração na matéria, entre as radiações ionizantes alfa, beta e gama, as radiações gama são as que possuem maior poder de penetração.'], correctIndex: 4 },
  { id: 'ufpr_2019_101_091', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Considerando que a vigilância em saúde é essencial para a identificação dos problemas de saúde e agravos que incidem sobre a saúde da população e para o planejamento de estratégias de intervenção, o Ministério da Saúde vem salientando a importância de que as ações de vigilância no SUS incorporem a Vigilância em Saúde do Trabalhador e da Trabalhadora (VISAT). A respeito do assunto, é correto afirmar:', options: ['Cabe à Unidade Básica de Saúde a identificação das ocupações da população e as atividades produtivas existentes no território, levantando as situações de risco à saúde dos(as) trabalhadores(as) do território para subsidiar as ações de prevenção.', 'As ações da VISAT devem ser executadas pelas Unidades Básicas de Saúde de cada município.', 'O aprimoramento da assistência clínica é prioridade das ações da VISAT.', 'Compete aos fiscais do trabalho (do Ministério do Trabalho, atualmente da Secretaria de Trabalho do Ministério da Economia) a identificação dos riscos a que estão expostos o trabalhador e trabalhadora, em cada estabelecimento produtivo.', 'A VISAT compete à esfera estadual do SUS de acordo com o que é preconizado na PNSTT e no Caderno de Atenção Básica sobre Saúde do Trabalhador e da Trabalhadora.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_092', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Homem de 46 anos trabalha há 20 anos como serralheiro em oficina nos fundos de sua casa, sem registro trabalhista e sem recolhimento previdenciário. Ao procurar emprego registrado, é submetido a exame médico de admissão e realiza audiometria cujo resultado mostra perda auditiva neurosensorial bilateral moderada, 50dB em 4kHz. Em relação ao caso, considere as seguintes afirmativas: 1. Classifica-se como perda neurosensorial bilateral, já de grau moderado, 50dB em 4kHz. 2. Enquadra-se como doença relacionada ao trabalho (PAIR), mesmo sendo autônomo. 3. Trata-se de perda chamada sintomática, com falha na capacidade de comunicação verbal pelas faixas de perda. 4. Como o paciente vai trabalhar 08 horas/dia em ambiente exposto a ruído entre 75 e 80 dB(A), o Atestado de Saúde Ocupacional – ASO será emitido como "INAPTO". Assinale a alternativa correta.', options: ['Somente a afirmativa 2 é verdadeira.', 'Somente as afirmativas 1 e 4 são verdadeiras.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2 e 3 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 3 },
  { id: 'ufpr_2019_101_093', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Um auxiliar de produção industrial recebe atendimento médico no ambulatório da empresa onde trabalha, administrado pelo plano de saúde. Relata ardência em abdome e parte anterior de coxas há dois ou três meses. Diz trabalhar com alguma frequência com seu uniforme molhado de solvente orgânico (ciclohexano + acetona). Ao exame, tem eritema local, aspecto liquenificado, áreas de fissuras e pouca exsudação. Em relação às condutas médicas necessárias nesse caso, considere as seguintes afirmativas: 1. Por não ser um caso crônico, não existe equiparação legal na saúde do trabalhador. 2. O caso é de doença de notificação compulsória para todos os médicos através do SINAN, segundo Portaria do Ministério da Saúde. 3. A ficha de notificação a ser utilizada será a de "Dermatose Ocupacional". 4. É procedimento ético do médico informar o diagnóstico utilizando o "CID" tanto nas CAT quanto nas Fichas SINAN mesmo sem a autorização expressa do paciente. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 2 e 4 são verdadeiras.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2 e 3 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_094', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina de Família', text: 'Uma paciente procurou primeiramente atendimento de um especialista em ouvido, nariz e garganta (ONG) por causa de terríveis dores de cabeça e um autodiagnóstico de sinusite. O médico ONG pediu uma tomografia computadorizada e, depois, receitou esteroides para a sinusite, mas as dores de cabeça da paciente pioraram. Nesse ínterim, ela procurou seu ginecologista para um check-up de rotina, que a aconselhou a parar de tomar as pílulas anticoncepcionais e a encaminhou a um neurologista que diagnosticou enxaqueca e receitou medicamentos para esse problema. Logo em seguida, ela desenvolveu falhas na fala, o que levou o neurologista a aumentar a dose. A não remissão dos sintomas fez com que ela consultasse seu médico de família, que pediu exames para a função da glândula tireoide. Diagnóstico: hipertireoidismo. A paciente agora está assintomática e voltou a trabalhar, tomando medicamentos para seu problema. O caso evidencia a importância dos atributos da atenção primária de:', options: ['apoio matricial e responsabilidade.', 'integralidade e acessibilidade.', 'universalidade e descentralização.', 'atuação comunitária e educação em saúde.', 'participação popular e efetividade.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_095', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina de Família', text: 'Com base no caso clínico da paciente que peregrinou entre especialistas (ONG, ginecologista, neurologista, médico de família) até o diagnóstico de hipertireoidismo, é correto afirmar:', options: ['Para qualquer queixa apresentada, a probabilidade de verdadeira enfermidade será mais alta na população de atenção primária do que nas práticas de atendimento nos níveis secundário e terciário.', 'Os médicos de atenção primária pedirão mais exames e procedimentos que os médicos especialistas dos níveis secundário e terciário.', 'A probabilidade de que um determinado exame diagnóstico diagnosticará corretamente uma condição em um determinado paciente depende da frequência provável daquela doença nos pacientes que o médico examina.', 'A capacitação dos médicos de níveis secundário e terciário se dá com pessoas que apresentam baixa probabilidade de ter um problema raro ou sério.', 'Se muitas pessoas com baixa probabilidade da enfermidade forem submetidas a exames, na maioria das vezes ele terá resultados precisos.'], correctIndex: 2 },
  { id: 'ufpr_2019_101_096', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'A partir dos conhecimentos de Sistemas de Saúde e dos Níveis de Prevenção de Doenças, assinale a alternativa correta.', options: ['No que se refere à equidade no processo de cuidado, há estudos que mostram que médicos atendem melhor os pacientes mais jovens, bonitos e bem vestidos, mais instruídos e que muitas vezes exigem menos serviços.', 'Os sistemas públicos de saúde de cobertura universal fundam-se na equidade, o que significa garantir a liberdade dos usuários em ir diretamente a todos os níveis do sistema.', 'Programas que promovam a redução de quedas em idosos e diminuição na sua mobilidade, são considerados de prevenção secundária.', 'Nos países desenvolvidos, a classe alta foi a primeira a iniciar o fumo do tabaco, seguida pela classe pobre, e essa classe alta segue sendo a com maior prevalência do tabagismo.', 'O conjunto de exames e testes realizados em pacientes assintomáticos, os chamados check-ups, possui grande segurança ao demonstrar a normalidade da saúde.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_098', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina de Família', text: 'João, 42 anos, no consultório da médica da família, relata se sentir bem, não ter nenhum problema de saúde, fazer atividade física (academia três vezes por semana), ter melhorado a alimentação nos últimos anos e estar com peso adequado. Ainda assim, manifesta vontade de realizar check-up completo. Em relação ao rastreamento de doenças, assinale a alternativa correta.', options: ['O objetivo principal do rastreamento é o diagnóstico precoce.', 'Qualquer teste usado como rastreamento apresentará como resultados do mais frequente para o menos frequente: verdadeiro-positivos, falso-negativos, verdadeiro-negativos e falso-positivos.', 'A médica deve explicar ao paciente os prós e contras do rastreio, e orientar que, para o perfil dele, estaria bem indicado um teste ergométrico.', 'O rastreio populacional do câncer de pulmão é indicado com raios X de tórax, a cada 2 anos, a partir dos 50 anos.', 'Há fortes evidências científicas de que o rastreio populacional de câncer de próstata reduz mortalidade específica e geral.'], correctIndex: 0 },
  { id: 'ufpr_2019_101_099', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'De acordo com os marcos legais do SUS, considere as seguintes afirmativas: 1. Igualdade na assistência à saúde reitera que não pode existir discriminação no acesso aos serviços de saúde, ou seja, não é aceitável que somente alguns grupos tenham acesso a determinados serviços e outros não. 2. Equidade significa o atendimento aos indivíduos de acordo com suas necessidades, oferecendo mais a quem mais precisa e menos a quem precisa de menos cuidados. 3. Integralidade é entendida como um conjunto articulado e contínuo de ações e serviços preventivos e curativos, individuais e coletivos, exigidos para cada caso em todos os níveis de complexidade do sistema. 4. Universalidade é a expressão de que todos têm o mesmo direito de obter as ações e os serviços de que necessitam, independentemente de complexidade, custo e natureza dos serviços envolvidos. Assinale a alternativa correta.', options: ['As afirmativas 1, 2, 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 3 e 4 são verdadeiras.', 'Somente as afirmativas 2 e 4 são verdadeiras.', 'Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente a afirmativa 2 é verdadeira.'], correctIndex: 1 },
  { id: 'ufpr_2019_101_100', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Com a criação do Sistema Único de Saúde, a responsabilidade pela assistência à saúde deixa de ser centralizada no âmbito federal e passa a ser descentralizada político-administrativamente. Em relação ao tema, assinale a alternativa correta.', options: ['Um dos limites da descentralização é a falta de regulação federal sobre ela, o que faz com que as políticas públicas municipais sejam heterogêneas entre as diversas regiões do país.', 'Um dos motivos que garantiu a descentralização do Sistema Único de Saúde no Brasil foi a inexistência de encargos sociais compartilhados entre os governos.', 'O tipo de descentralização político-administrativo garante a transferência da gestão de serviços públicos para estados e municípios, mas não do poder decisório e da responsabilidade sobre o conjunto de prestadores do Sistema Único de Saúde.', 'A descentralização do Sistema Único de Saúde esbarra em dificuldades institucionais de financiamento, e o próprio avanço do processo evidencia problemas estruturais do sistema de saúde.', 'O tema da descentralização do sistema de saúde brasileiro se inicia com a 8ª Conferência Nacional de Saúde, de 1986, com o intuito de garantir a democratização na Constituição de 1988 e incorporação da participação popular.'], correctIndex: 3 },
];
